/* ── Reusable Components ── */

function HoverCard({ children, style, hoverBorder }) {
  const [hovered, setHovered] = useState(false)
  return (
    <div onMouseEnter={() => setHovered(true)} onMouseLeave={() => setHovered(false)}
      style={{ background: T.surface, border: `1px solid ${hovered ? (hoverBorder || T.blue) : T.border}`, borderRadius: 14, padding: 32, transition: 'all 0.25s ease', transform: hovered ? 'translateY(-4px)' : 'translateY(0)', boxShadow: hovered ? '0 12px 40px rgba(0,0,0,0.4)' : '0 2px 8px rgba(0,0,0,0.2)', ...style }}>
      {children}
    </div>
  )
}

function AlgoCard({ name, icon, color, description, specs }) {
  const [hovered, setHovered] = useState(false)
  return (
    <div onMouseEnter={() => setHovered(true)} onMouseLeave={() => setHovered(false)}
      style={{
        background: T.surface, border: `1px solid ${hovered ? color : T.border}`, borderRadius: 14,
        padding: 32, transition: 'all 0.25s ease',
        transform: hovered ? 'translateY(-4px)' : 'none',
        boxShadow: hovered ? `0 12px 40px rgba(0,0,0,0.4), 0 0 20px ${color}15` : '0 2px 8px rgba(0,0,0,0.2)',
        position: 'relative', overflow: 'hidden',
      }}>
      <div style={{
        position: 'absolute', top: 0, left: 0, right: 0, height: 3,
        background: `linear-gradient(90deg, ${color}, ${color}44)`,
      }} />
      <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 16 }}>
        <div style={{
          width: 44, height: 44, borderRadius: 10, background: `${color}15`,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 18, fontWeight: 800, fontFamily: T.monoFont, color, border: `1px solid ${color}30`,
        }}>{icon}</div>
        <div style={{ fontSize: 22, fontWeight: 700 }}>{name}</div>
      </div>
      <p style={{ fontSize: 14, color: T.textSecondary, lineHeight: 1.65, margin: '0 0 16px' }}>{description}</p>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
        {specs.map((s, i) => (
          <div key={i} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '6px 0', borderTop: `1px solid ${T.border}` }}>
            <span style={{ fontSize: 13, color: T.textSecondary }}>{s.label}</span>
            <span style={{ fontSize: 13, fontFamily: T.monoFont, fontWeight: 600, color: T.textPrimary }}>{s.value}</span>
          </div>
        ))}
      </div>
    </div>
  )
}

function LatencyStat({ value, unit, label }) {
  return (
    <div style={{ textAlign: 'center', flex: 1, minWidth: 140 }}>
      <div style={{ display: 'flex', alignItems: 'baseline', justifyContent: 'center', gap: 4 }}>
        <span style={{ fontFamily: T.monoFont, fontSize: 36, fontWeight: 800, color: T.green }}>{value}</span>
        <span style={{ fontFamily: T.monoFont, fontSize: 16, fontWeight: 600, color: T.textSecondary }}>{unit}</span>
      </div>
      <div style={{ fontSize: 13, color: T.textSecondary, marginTop: 8 }}>{label}</div>
    </div>
  )
}

function QualityMetric({ label, value, color, barPct }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 16, padding: '10px 0' }}>
      <span style={{ fontSize: 13, color: T.textSecondary, width: 140, flexShrink: 0 }}>{label}</span>
      <div style={{ flex: 1, height: 8, background: T.border, borderRadius: 6, overflow: 'hidden' }}>
        <div style={{ width: `${barPct}%`, height: '100%', background: color, borderRadius: 6, transition: 'width 0.4s ease' }} />
      </div>
      <span style={{ fontFamily: T.monoFont, fontSize: 13, color, width: 56, textAlign: 'right', fontWeight: 600 }}>{value}</span>
    </div>
  )
}

function RoutingStep({ number, title, desc, accent }) {
  return (
    <div style={{ flex: 1, textAlign: 'center', position: 'relative', minWidth: 180 }}>
      <div style={{
        width: 52, height: 52, borderRadius: '50%', background: `${accent}18`,
        border: `2px solid ${accent}`, display: 'flex', alignItems: 'center', justifyContent: 'center',
        margin: '0 auto 14px', fontSize: 22, fontWeight: 700, fontFamily: T.monoFont, color: accent,
      }}>{number}</div>
      <div style={{ fontSize: 16, fontWeight: 700, marginBottom: 8 }}>{title}</div>
      <div style={{ fontSize: 13, color: T.textSecondary, lineHeight: 1.6 }}>{desc}</div>
    </div>
  )
}

function CTAButton({ to, label, primary }) {
  const [hovered, setHovered] = useState(false)
  return (
    <Link to={to} onMouseEnter={() => setHovered(true)} onMouseLeave={() => setHovered(false)}
      style={{
        display: 'inline-block', padding: '14px 36px', borderRadius: 10, fontSize: 14, fontWeight: 600,
        textDecoration: 'none', transition: 'all 0.25s ease',
        background: primary ? (hovered ? '#4DB860' : T.green) : 'transparent',
        color: primary ? '#000' : T.textPrimary,
        border: primary ? 'none' : `1px solid ${hovered ? T.textPrimary : T.border}`,
        transform: hovered ? 'translateY(-2px)' : 'none',
        boxShadow: primary && hovered ? '0 8px 24px rgba(63,185,80,0.3)' : 'none',
      }}>
      {label}
    </Link>
  )
}

